import { useState } from "react";

const CHUNKS = ["","","",""];

export default function HuGoDownloader() {
  const [status, setStatus] = useState("idle");

  function download() {
    setStatus("working");
    try {
      const b64 = CHUNKS.join("");
      const binary = atob(b64);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
      const blob = new Blob([bytes], { type: "text/html" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url; a.download = "index.html";
      document.body.appendChild(a); a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      setStatus("done");
    } catch(e) { setStatus("error"); }
  }

  const steps = [
    ["1","Go to github.com/Dilcue16/HuGo-02"],
    ["2","Click + → Upload files"],
    ["3","Drag index.html into the box"],
    ["4","Click Commit changes"],
    ["✓","Wait 2-3 min → open your GitHub Pages URL"]
  ];

  return (
    <div style={{minHeight:"100vh",background:"#0C447C",display:"flex",alignItems:"center",justifyContent:"center",padding:"20px",fontFamily:"-apple-system,BlinkMacSystemFont,sans-serif"}}>
      <div style={{background:"#fff",borderRadius:"20px",padding:"32px 28px",maxWidth:"380px",width:"100%"}}>
        <div style={{textAlign:"center",marginBottom:"24px"}}>
          <div style={{width:"72px",height:"72px",borderRadius:"50%",background:"#0C447C",margin:"0 auto 16px",display:"flex",alignItems:"center",justifyContent:"center"}}>
            <span style={{color:"#fff",fontSize:"20px",fontWeight:"700"}}>HuGo</span>
          </div>
          <h2 style={{fontSize:"20px",fontWeight:"700",color:"#0C447C",margin:"0 0 4px"}}>Human Rights on the Go</h2>
          <p style={{fontSize:"13px",color:"#7a8a9a",margin:0}}>BULPPO · PRO 3 · PWA Package</p>
        </div>

        <button onClick={download} disabled={status==="working"} style={{
          width:"100%",padding:"15px",
          background:status==="done"?"#3B6D11":status==="error"?"#A32D2D":"#0C447C",
          color:"#fff",border:"none",borderRadius:"14px",
          fontSize:"15px",fontWeight:"700",cursor:status==="working"?"wait":"pointer",
          marginBottom:"16px"
        }}>
          {status==="idle" && "⬇ Download index.html"}
          {status==="working" && "⏳ Preparing..."}
          {status==="done" && "✓ Downloaded! Upload to GitHub"}
          {status==="error" && "✗ Error — try again"}
        </button>

        {status==="done" && <div style={{background:"#EAF3DE",border:"1px solid #C0DD97",borderRadius:"10px",padding:"10px 12px",fontSize:"12px",color:"#3B6D11",marginBottom:"16px"}}>
          ✓ index.html saved to your Downloads folder — now upload it to GitHub
        </div>}

        <div style={{borderTop:"1px solid #f0f4f8",paddingTop:"14px"}}>
          <p style={{fontSize:"11px",fontWeight:"700",color:"#94a3b8",textTransform:"uppercase",letterSpacing:"0.5px",margin:"0 0 10px"}}>After downloading:</p>
          {steps.map(([num,text])=>(
            <div key={num} style={{display:"flex",alignItems:"flex-start",gap:"10px",marginBottom:"8px"}}>
              <div style={{width:"24px",height:"24px",borderRadius:"50%",flexShrink:0,background:num==="✓"?"#3B6D11":"#0C447C",color:"#fff",display:"flex",alignItems:"center",justifyContent:"center",fontSize:"11px",fontWeight:"700"}}>{num}</div>
              <p style={{fontSize:"12px",color:"#5a6a7a",margin:"3px 0 0",lineHeight:"1.4"}}>{text}</p>
            </div>
          ))}
        </div>

        <div style={{marginTop:"14px",background:"#f8fafc",borderRadius:"10px",padding:"10px 12px"}}>
          <p style={{fontSize:"11px",color:"#94a3b8",margin:"0 0 4px",fontWeight:"700"}}>CREDENTIALS</p>
          <p style={{fontSize:"11px",color:"#5a6a7a",margin:0,fontFamily:"monospace",lineHeight:"1.8"}}>
            Station passcode: PHRA2025<br/>
            Super user: HUGO@ADMIN2025<br/>
            Camera token: HUGO-INSPECT-01
          </p>
        </div>
      </div>
    </div>
  );
}